import 'package:flutter/material.dart';
import 'package:get/get.dart';
import 'package:get_storage/get_storage.dart';

void main() async {
  await GetStorage.init();
  runApp(MyApp());
}

class SettingsController extends GetxController {
  final storage = GetStorage();
  var username = ''.obs;

  @override
  void onInit() {
    super.onInit();
    // Load saved username
    username.value = storage.read('username') ?? '';
    // Save when changed
    ever(username, (value) {
      storage.write('username', value);
    });
  }

  void setUsername(String name) {
    username.value = name;
  }
}

class MyApp extends StatelessWidget {
  final controller = Get.put(SettingsController());

  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('State Persistence')),
        body: Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Obx(() => Text('Saved username: ${controller.username.value}', style: TextStyle(fontSize: 20))),
              SizedBox(height: 20),
              TextField(
                onChanged: controller.setUsername,
                decoration: InputDecoration(labelText: 'Enter username'),
              ),
              SizedBox(height: 10),
              ElevatedButton(
                onPressed: () => controller.setUsername(''),
                child: Text('Clear'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}
